const fs = require('fs');
const path = require('path');

const newQuestions = [
  { id: 73, sectionId: 7, title: '[Real Exam] Code Review – Severity Consistency', text: 'Your automated code review system shows inconsistent severity ratings — similar issues like null pointer risks receive critical severity in some PRs but only medium in others. Developer trust is declining because teams cannot predict which findings require immediate attention. What is the most effective way to improve severity consistency?', options: { A: 'Request that Claude include its reasoning for each severity assignment, then use that reasoning to manually calibrate ratings during review', B: 'Include explicit severity criteria in your prompt with concrete code examples for each severity level', C: 'Add a CLAUDE.md file that lists issue types and their default severities, instructing Claude to reference this mapping when assigning severity', D: 'Modify the prompt to ask Claude to rate severity relative to other issues in the same PR, so the most severe issue is always marked critical' }, correctAnswer: 'B', explanation: 'Without a rubric, Claude infers severity inconsistently. Explicit criteria with concrete code examples for each level gives Claude a grounded definition to match patterns to labels consistently.' },
  { id: 74, sectionId: 7, title: '[Real Exam] Claude Code – Automated Pipeline', text: 'Your pipeline script runs `claude "analyze this and report for security issues"` but the job hangs indefinitely. Claude Code is waiting for user input. What is the best approach to run Claude Code in an automated pipeline?', options: { A: 'Redirect stdin from /dev/null', B: 'Add the --batch flag to the command', C: 'Add the -p flag: `claude -p "analyze this and report for security issues"`', D: 'Set an environment variable to enable non-interactive mode before running' }, correctAnswer: 'C', explanation: 'The -p (print/non-interactive) flag tells Claude Code to run once, output result to stdout, then exit without waiting for user input — the designed solution for CI/CD pipelines.' },
  { id: 75, sectionId: 7, title: '[Real Exam] Code Review – False Positive Rate', text: 'Analysis shows Security & correctness findings have 4% FP rate, style & naming have 45% FP rate, and documentation findings have 48% FP rate. Developers have started dismissing findings without review. What approach best restores developer trust while improving the system?', options: { A: 'Keep all categories enabled while adding few-shot examples to improve each category accuracy over the coming weeks', B: 'Apply a uniform strictness reduction across all categories to bring the overall false positive rate to an acceptable level', C: 'Keep all categories but display a confidence score with each finding, letting developers decide which to investigate', D: 'Temporarily disable high false-positive categories (style, naming, documentation) and run only high-precision categories while improving precision' }, correctAnswer: 'D', explanation: 'High-FP categories destroy trust in accurate categories. D surgically keeps high-precision categories running while fixing noisy ones offline, restoring trust immediately.' },
  { id: 76, sectionId: 2, title: '[Real Exam] Batch API – Document Routing', text: 'Your extraction system processes standard monthly reports (archived after processing) and urgent exception reports (need trigger actions within 1 hour). Both use the same JSON schema. You want to minimize API costs while meeting latency requirements. How should you architect the processing pipeline?', options: { A: 'Submit all documents to the real-time Messages API to ensure consistent processing latency across document types', B: 'Route standard reports to the Batch API for 50% cost savings, and route urgent exception reports to the real-time Messages API', C: 'Queue all documents and submit hourly batches, flagging urgent documents for expedited handling', D: 'Submit all documents to the Batch API with custom_ids for tracking, immediately process urgent documents when results arrive' }, correctAnswer: 'B', explanation: 'Match each document type to the right API: Batch API for cost savings on non-urgent reports, real-time Messages API for the 1-hour SLA on urgent exceptions.' },
  { id: 77, sectionId: 2, title: '[Real Exam] Structured Output – JSON Reliability', text: 'Your extraction pipeline occasionally receives responses that do not parse as valid JSON, causing downstream processing failures. What is the most reliable approach to ensure Claude returns valid, schema-compliant structured data?', options: { A: 'Add explicit formatting instructions to the prompt with JSON examples, emphasizing that Claude must return only valid JSON with no surrounding text', B: 'Use regular expressions to locate and extract JSON from the response text, handling cases where Claude includes explanatory text', C: 'Define a tool with a JSON schema specifying the expected structure, using tool use to constrain Claude output to schema-compliant data', D: 'Implement a retry loop that catches JSON parse errors and re-prompts Claude with the error details, asking it to correct the validation issues' }, correctAnswer: 'C', explanation: 'Tool use with a JSON schema is API-level enforcement. Claude must fill structured parameters validated against the schema — an architectural constraint, not a prompt suggestion.' },
  { id: 78, sectionId: 2, title: '[Real Exam] Human Review – Semantic Errors', text: 'After deployment, 12% of extractions contain semantic errors that pass JSON schema validation (e.g., a duration like "30 minutes" stored in a numeric field expecting seconds). Human reviewers can only check 20% of extractions. Which approach most effectively allocates reviewer attention?', options: { A: 'Prioritize review of all extractions where required fields are empty or explicitly marked as not found', B: 'Randomly sample 20% of extractions for review, using corrections to track accuracy and identify error patterns', C: 'Have the model output field-level confidence scores, then calibrate review thresholds using a labeled validation set', D: 'Review all extractions from documents with formatting anomalies such as unusual layouts or mixed content types' }, correctAnswer: 'C', explanation: 'Field-level confidence scores with calibrated thresholds on a labeled validation set directs reviewers to extractions with the highest probability of semantic errors — risk-based prioritization.' },
  { id: 79, sectionId: 2, title: '[Real Exam] Tool Use – Forcing Specific Tools', text: 'Your pipeline uses `extract_metadata` with a JSON schema. You also defined `citation_formatter` and `reference_list` tools. Claude sometimes calls `citation_formatter` first, which fails because structured metadata extraction must happen first. What is the most effective way to ensure `extract_metadata` is called first?', options: { A: 'Set `tool_choice` to "any" so Claude must use a tool, combined with system prompt instructions prioritizing `extract_metadata`', B: 'Set `tool_choice` to {"type": "tool", "name": "extract_metadata"} and process subsequent calls in the pipeline', C: 'Set `tool_choice` to "auto" and reorder the tool definitions so `extract_metadata` appears first', D: 'Set `tool_choice` to "auto" so `extract_metadata` appears first in the tool array, ensuring Claude prioritizes it' }, correctAnswer: 'B', explanation: 'tool_choice: {"type": "tool", "name": "extract_metadata"} forces Claude to call that specific tool. "any" and "auto" only suggest or require some tool — they do not guarantee which one.' },
  { id: 80, sectionId: 2, title: '[Real Exam] Semantic Validation – Retry Logic', text: 'Your invoice extraction uses tool use with strict JSON schemas. JSON syntax errors never occur, but 12% of extractions fail semantic validation (line items do not sum to total, vendor IDs wrong format). These currently route to manual review. What is the most effective approach to reduce manual review while maintaining accuracy?', options: { A: 'Implement post-processing logic that automatically corrects common errors, such as recalculating total from line items when sums do not match', B: 'When validation fails, make a follow-up request with the document, extraction, and validation errors for model correction', C: 'Retry the extraction up to 3 times when validation fails, accepting the first result that passes validation', D: 'Add stricter schema constraints with detailed field descriptions to prevent the model from generating invalid values' }, correctAnswer: 'B', explanation: 'Targeted correction with validation error context lets Claude see the original document, what it extracted, and exactly what failed — enabling precise fixes with full context.' },
  { id: 81, sectionId: 2, title: '[Real Exam] Retry Logic – When It Fails', text: 'Your extraction system implements automatic retries when validation fails. Each retry appends the specific validation error to the prompt and resolves most failures within 2-3 attempts. For which failure pattern would additional retries be LEAST effective?', options: { A: 'The model extracts citation counts as locale-formatted strings ("1,234") when the schema requires integers', B: 'The model extracts keywords as a nested object organized by category when the schema requires a flat array of strings', C: 'The model extracts "et al." for co-authors when the full author list exists only in an external document not in the input', D: 'The model extracts dates as ISO 8601 datetime strings ("2023-03-15T00:00:00") when the schema requires only the date portion' }, correctAnswer: 'C', explanation: 'Retries fix how Claude outputs data, not what data is available. The full co-author list does not exist in the input — no amount of retrying can produce information that is not there.' },
  { id: 82, sectionId: 2, title: '[Real Exam] Conflicting Data Sources', text: 'Specifications sometimes appear inconsistently within source documents. A summary section might state "Battery: 4000mAh" while the detailed specs table shows "Battery: 4200mAh." Your schema uses a single `battery_capacity_mah` field. The detailed specs table is more accurate 90% of the time. What is the most effective approach?', options: { A: 'Implement schema validation that rejects results containing conflicting values, requiring manual review for affected documents', B: 'Add a `conflict_detected` boolean field that flags inconsistencies, triggering manual review for affected documents', C: 'Include extraction instructions specifying to prefer values from the detailed specs table when multiple values exist', D: 'Change to an array field that captures all values found with their source locations, letting downstream systems apply preference rules' }, correctAnswer: 'C', explanation: 'You already know the detailed specs table is more reliable 90% of the time. Apply that knowledge directly at extraction time rather than routing to manual review or over-engineering with arrays.' },
  { id: 83, sectionId: 2, title: '[Real Exam] Context Window – Tool Definition Tokens', text: 'Your extraction system uses tool use with a JSON schema containing 12 fields totaling approximately 2,100 tokens. For documents under 150K tokens, accuracy is 98%. For documents between 135–190K tokens, accuracy drops to 71%, with information from the first half rarely extracted accurately. What is the most likely cause?', options: { A: 'Very long documents exceed the model effective attention span regardless of context limits', B: 'Schemas exceeding 8-10 fields increase decision complexity during parameter generation, independent of document length', C: 'Tool definitions consume input context tokens. Combined with system prompts and document content, the total approaches or exceeds the context window, causing truncation of earlier document content', D: 'The model distributes attention proportionally across input context length, causing fields mentioned early to receive less relative attention' }, correctAnswer: 'C', explanation: 'Document (150–190K) + tool definition (~2,100) + system prompt approaches the 200K context window. When exceeded, earlier content gets truncated — explaining why the first half is not extracted accurately.' },
  { id: 84, sectionId: 2, title: '[Real Exam] Long Document Strategy', text: 'Evaluation shows 94% extraction accuracy on short meeting transcripts (<30 minutes) but only 64% on longer transcripts (>60 minutes) where key decisions are scattered throughout. Both lengths fit within the model context window. What pattern most effectively improves accuracy on longer documents?', options: { A: 'Add few-shot examples demonstrating correct extraction from lengthy meetings with scattered information', B: 'Upgrade to a more capable model tier for the extraction task', C: 'Split lengthy transcripts into chunks, extract from each chunk separately, then merge and deduplicate the results', D: 'Add a pre-extraction step where the model summarizes key discussions and conclusions, then perform extraction on that summary' }, correctAnswer: 'D', explanation: 'This is a signal-to-noise problem, not truncation. A 2-step pipeline — summarize first to concentrate signal, then extract from the clean summary — addresses scattered information in long transcripts.' },
  { id: 85, sectionId: 2, title: '[Real Exam] Output Normalization', text: 'Your extraction pipeline processes restaurant menus and must output structured JSON with fields for item names, descriptions, prices, and dietary info. Source menus are inconsistent: prices appear as "$12" vs "12.00", dietary info as icons vs text. What is the most reliable approach for consistent output?', options: { A: 'Use separate extraction calls for each field to ensure consistent handling of each type', B: 'Extract data as-is and normalize formats in post-processing code after Claude returns', C: 'Define a strict output schema AND include format normalization rules in your prompt', D: 'Request multiple extraction attempts per document and select the most common format' }, correctAnswer: 'C', explanation: 'Two-layer enforcement: strict schema defines structure and types; normalization rules in the prompt tell Claude how to convert (e.g., extract prices as numeric values without currency symbols).' },
  { id: 86, sectionId: 2, title: '[Real Exam] Few-Shot Examples – Nuanced Behavior', text: 'Your schema includes a `skills: string[]` field. Production monitoring reveals: (1) compound phrases like "Python and SQL" are occasionally split, (2) implied but unstated skills occasionally appear, (3) similar documents produce wildly different array lengths (2–16 entries). Your prompt currently says "list all skills mentioned." What is the most effective improvement?', options: { A: 'Add post-extraction normalization that maps skills to a canonical taxonomy and deduplicates similar entries', B: 'Add constraints: "Extract 10–20 skills maximum, one skill per entry, only explicitly named skills"', C: 'Enrich the schema to `{skill: string, confidence: float, source: string}` to capture extraction metadata', D: 'Add few-shot examples demonstrating compound phrase handling, explicit mention criteria, and appropriate entry volumes' }, correctAnswer: 'D', explanation: 'All three problems are nuanced behavioral issues. Few-shot examples show Claude exactly how to handle compound phrases, implied skills, and appropriate entry counts — addressing all three simultaneously.' },
  { id: 87, sectionId: 2, title: '[Real Exam] Batch Processing Strategy', text: 'Your team is extracting structured data from 50,000 legacy legal contracts under a two-week deadline. Initial testing with 500 sample documents achieves 82% success on the first attempt. Which batch processing strategy is most cost-efficient while still meeting the deadline?', options: { A: 'Use the real-time API for all 50,000 documents since the batch API 24-hour processing window creates unacceptable deadline risk', B: 'Split documents into 10 sequential batches of 5,000 each, analyzing results and refining prompts between batches', C: 'Submit all 50,000 documents via batch API, then submit failed extractions via real-time API to identify failure patterns', D: 'Process ~2,000 sample documents via real-time API to identify failure patterns and refine prompts, then batch process all 50,000 with the corrected prompt' }, correctAnswer: 'D', explanation: 'Learn first, scale second: real-time on 2,000 docs surfaces failure patterns, refine prompts, then submit all 50,000 via Batch API for 50% cost savings within the two-week deadline.' },
  { id: 88, sectionId: 7, title: '[Real Exam] Multi-Domain Prompts', text: 'Your automated reviewer uses a single prompt covering security issues, API design, and business logic correctness. Business logic edge cases achieve only 34% recall. When you add few-shot examples for business logic, recall improves to 47% but API design recall drops. How do you address this trade-off?', options: { A: 'Split the review into separate focused prompts — one for security and API design, another for business logic — each with dedicated examples', B: 'Provide the full repository as context instead of just the changed files to give the model deeper visibility', C: 'Upgrade to a more capable model tier, since its stronger reasoning will handle both concern types in a single prompt', D: 'Replace the few-shot examples with a detailed checklist of specific logic edge cases to verify' }, correctAnswer: 'A', explanation: 'One prompt covering multiple review types forces Claude to split focus. Splitting into domain-focused prompts with dedicated examples eliminates the competing attention problem.' },
  { id: 89, sectionId: 7, title: '[Real Exam] Branch-Level Coverage', text: 'Your code review prompts include both implementation changes and the corresponding test file. The LLM correctly flags functions with no tests but fails to identify when conditional branches or error handling paths within tested functions lack coverage. What is the most effective way to improve detection without overcomplicating the pipeline?', options: { A: 'Add explicit instructions directing the model to enumerate each conditional branch and exception path, then verify each has a corresponding test case', B: 'Include few-shot examples showing code with an uncovered branch paired with the review comment identifying the specific missing test case', C: 'Restructure the prompt to use two separate LLM calls: first extract all conditional branches, then identify missing coverage', D: 'Implement a multi-pass pipeline where separate LLM calls first extract branches, then identify missing coverage' }, correctAnswer: 'B', explanation: 'Claude understands missing tests at the function level but not branch-level gaps. Few-shot examples directly teach this pattern recognition in a single pass without over-complicating the pipeline.' },
  { id: 90, sectionId: 7, title: '[Real Exam] Cross-File Bug Detection', text: 'Your pipeline reviews every PR using a single API call with a static prompt containing the diff and full text of each changed file. Reviews consistently miss bugs involving cross-file interactions. Cross-file bugs account for 35% of production incidents. What is the most cost-effective change?', options: { A: 'Redesign the review as a turn-limited agentic task where the model can read files and search the codebase via tools', B: 'Run parallel review passes per changed file with direct dependents included in each pass, then aggregate findings', C: 'Use static analysis to build a dependency graph of changed code, then expand the prompt to include all files within two hops of the changed files', D: 'Add chain-of-thought instructions asking the model to list all external references in the diff, then reason about cross-file impact' }, correctAnswer: 'C', explanation: 'Static analysis deterministically identifies dependent files. Include files within 2 hops in one API call — most cost-effective because it adds only relevant context without multiple tool calls or parallel passes.' },
  { id: 91, sectionId: 10, title: '[Real Exam] CLAUDE.md – Suppressing False Positives', text: 'The automated review consistently flags patterns your team uses intentionally: force-unwrapping optionals in test files, using large coordinate structs, importing internally-maintained deprecated modules. Developers are dismissing roughly 30% of all findings. What prevents the model from generating these findings by supplying project conventions as persistent context?', options: { A: 'Build post-processing keyword filters that suppress findings containing terms like "force unwrap" or "deprecated import"', B: 'Document the team accepted patterns and intentional conventions in the project CLAUDE.md file', C: 'Have developers add inline suppress-comments at flagged lines in the diff', D: 'Configure the review to analyze only the changed lines in the diff without surrounding file context' }, correctAnswer: 'B', explanation: 'CLAUDE.md is the designed mechanism for project-level persistent context. Claude reads team conventions before every review and stops generating false positives for intentional patterns.' },
  { id: 92, sectionId: 7, title: '[Real Exam] Claude Code – Resource Caps', text: 'During testing, reviews on large PRs (50+ changed files) sometimes take over 30 minutes and cost $12 per run. Your team needs each invocation to abort once it reaches a fixed iteration count AND a hard dollar amount — enforced by Claude Code itself, not the surrounding job runner. Which configuration change directly enforces both caps?', options: { A: 'Add `--max-turns 10 --max-budget-usd 2.00` to the `claude` invocation', B: 'Switch the --model flag to a smaller, cheaper model so each iteration uses fewer tokens', C: 'Set `timeout-minutes: 5` on the GitHub Actions job step and monitor per-run costs via Anthropic Console', D: 'Set `--permission-mode dontAsk` to auto-deny any tool permission requests not in the explicitly allowed set' }, correctAnswer: 'A', explanation: '--max-turns caps agentic iterations and --max-budget-usd caps dollar amount. Both flags are built into Claude Code CLI and enforced by Claude Code itself.' },
  { id: 93, sectionId: 7, title: '[Real Exam] Output Token Limit', text: 'Your automated review uses tool_use with a `report_findings` tool returning a JSON array. On a large PR touching 30+ files, the response hits the `max_tokens` limit and is truncated mid-JSON, causing the downstream parser to crash. What is the most effective way to handle this?', options: { A: 'Switch from tool_use to prompting Claude to return findings as a markdown list, reporting only critical and high severity findings', B: 'Add retry logic that detects truncated JSON and re-sends the request with instructions to report only critical/high severity findings', C: 'Split the review into multiple API calls that each analyze a subset of the changed files, then merge the resulting findings arrays', D: 'Increase `max_tokens` to the model maximum and instruct Claude to keep finding descriptions under 50 words each' }, correctAnswer: 'C', explanation: 'Too much output from a single call causes truncation. Split input into batches (5-10 files per call), merge findings arrays — scales as PR sizes grow without losing severity coverage.' },
  { id: 94, sectionId: 7, title: '[Real Exam] Batch API Feasibility', text: 'Your CI pipeline performs security-focused code reviews on approximately 50 PRs daily, currently costing $150/day. You are evaluating the Message Batches API for its 50% cost reduction. What factor most determines whether batch processing is actionable for this use case?', options: { A: 'Whether review feedback arriving up to 24 hours after PR creation remains actionable for your workflow', B: 'Whether reducing per-review latency from 30-60 seconds to near-instant matters for your workflow', C: 'Whether your result processing can handle reviews arriving in a different order than submitted', D: 'Whether you can structure each review as a single request without multi-turn refinement' }, correctAnswer: 'A', explanation: 'The Batch API trade-off is 50% cheaper but results take up to 24 hours. Whether developers can tolerate that delay is the binary, workflow-specific determining factor.' },
  { id: 95, sectionId: 7, title: '[Real Exam] Claude Code – Startup Time', text: 'Your automated review CI jobs take 18 seconds to initialize before Claude begins analyzing code. Profiling reveals the delay comes from auto-discovery of CLAUDE.md files throughout your monorepo. You need to cut startup time while ensuring reviews still enforce team coding standards in your top-level CLAUDE.md. What is the most effective approach?', options: { A: 'Run with `--bare` mode and pass `--append-system-prompt-file /CLAUDE.md` to explicitly load your project standards while skipping all auto-discovery', B: 'Keep the default initialization and add `--exclude-dynamic-system-prompt-sections` to reduce prompt size', C: 'Replace the default prompt entirely using `--system-prompt-file /CLAUDE.md`', D: 'Run with `--bare` mode and specify all review criteria directly in the `-p` prompt argument for each CI invocation' }, correctAnswer: 'A', explanation: '--bare skips auto-discovery (eliminates the 18-second monorepo scan). --append-system-prompt-file explicitly loads the top-level CLAUDE.md, preserving team standards.' },
  { id: 96, sectionId: 7, title: '[Real Exam] Precision vs Recall', text: 'After deploying automated code review, you notice high precision but low recall — real bugs are slipping through. The prompt instructs Claude to "only report high-confidence issues" and "err on the side of not commenting." What is the most effective way to substantially improve bug detection while keeping false positives manageable?', options: { A: 'Remove the conservative filtering instructions and prompt Claude to report all potential issues, then apply a programmatic filter to remove false positives', B: 'Expand the context window by including related test files, git history, and the module dependency graph', C: 'Split the review into a finding stage where Claude flags every potential issue with confidence and severity scores, then apply risk-scoring to maintain current precision levels', D: 'Add detailed few-shot examples demonstrating the bug categories Claude should flag with the instruction to maintain current precision levels' }, correctAnswer: 'C', explanation: 'Two-stage pipeline decouples recall from precision: Stage 1 detects all potential issues with scores (high recall), Stage 2 filters by risk score to surface only actionable findings (controlled precision).' },
  { id: 97, sectionId: 7, title: '[Real Exam] Self-Review Bias', text: 'A developer uses Claude Code to refactor a function during their development session. Before committing, they ask the same Claude session to review the code. A separate automated CI review catches several bugs that the same-session review missed. What best explains this discrepancy?', options: { A: 'The CI environment has access to the full codebase context while the local session only has the current file', B: 'Claude retains context about its prior reasoning in the session, making it less likely to question its own decisions', C: 'The CI review uses a more specific prompt tailored for catching bugs, while the developer request was more general', D: 'The extended session length caused the context window to fill with conversation history during the coding session' }, correctAnswer: 'B', explanation: 'Anchoring bias: Claude refactored the code and has reasoning in context for why it made each decision. When asked to review the same code, it is less likely to critically challenge its own prior decisions.' },
  { id: 98, sectionId: 2, title: '[Real Exam] Batch API – Cost Reduction', text: 'Your pipeline includes a release notes generation step that classifies and summarizes approximately 200 commits at the end of each weekly release cycle. Each commit requires a separate API call using a Sonnet-tier model. Results are not needed until the following morning (8+ hours acceptable wait). You want to reduce per-token API cost while keeping the same model and prompts. Which approach best reduces cost?', options: { A: 'Issue the 200 Messages API requests in parallel using concurrent connections, since concurrency lowers the per-token price', B: 'Concatenate all 200 commit messages into a single Messages API request', C: 'Submit the 200 requests to the Message Batches API with unique custom_ids, collect results next morning', D: 'Switch the summarization calls from Sonnet-tier to Haiku-tier model' }, correctAnswer: 'C', explanation: 'Batch API provides same model, same prompts, 50% cost savings, results within 24 hours. Concurrency does not lower per-token price; changing model or prompts violates the constraints.' },
  { id: 99, sectionId: 7, title: '[Real Exam] Prompt Filtering – Finding Suppression', text: 'Your automated code review is missing genuine bugs. Investigation reveals your review prompt includes: "Only flag critical issues that would cause immediate production failures. Ignore minor concerns and anything you are uncertain about." Which prompt change best resolves missed bugs without breaking structured, tagged output for downstream filtering?', options: { A: 'Enable extended thinking and instruct the model to reason step-by-step about each code change before producing its review', B: 'Remove all severity-related instructions from the prompt and let the model use its default judgment', C: 'Instruct the model to report ALL findings with a confidence level and severity tag, deferring filtering to downstream', D: 'Add a second review pass that re-reads the diff using the same prompt, looking for anything the first pass may have missed' }, correctAnswer: 'C', explanation: 'The problem is filtering inside the prompt. C fixes this by having Claude report everything with confidence/severity metadata while downstream filtering decides what to surface.' },
  { id: 100, sectionId: 7, title: '[Real Exam] Claude Code – Cross-File Tool Access', text: 'Your pipeline runs: `claude -p --dangerously-skip-permissions --system-prompt "$PROMPT" < diff.txt`. Reviews complete but Claude only comments on the piped diff — it never reads surrounding files. Which change will cause Claude to read related files?', options: { A: 'Stop piping the diff via stdin and instead embed the diff contents inside the prompt string', B: 'Replace `--system-prompt` with `--append-system-prompt` and add file navigation tools', C: 'Remove `--system-prompt` and add `--allowedTools` with file-reading tools', D: 'Keep `--system-prompt` AND add `--allowedTools` to include file-reading/code navigation tools' }, correctAnswer: 'D', explanation: 'You need both: system prompt for review instructions AND allowedTools for file-reading capability. --allowedTools controls what Claude can access; the system prompt contains the instructions.' },
  { id: 101, sectionId: 7, title: '[Real Exam] Feedback Loop – Dismissed Findings', text: 'You built an LLM-powered code review tool that outputs structured findings with `category` and `description`. Developers can click dismiss on findings they consider unhelpful — currently 30% are dismissed. What change to your output structure would best help you understand what your system is getting wrong?', options: { A: 'Add a `detected_pattern` field recording the code construct (e.g., "single-letter loop variable") that triggered each finding', B: 'Expand the `description` field to include more detailed explanations of why each issue matters and how to fix it', C: 'Remove the `issue_category` field and track dismissals at the individual finding level', D: 'Add a `model_confidence` field (0.0–1.0) and filter out findings below a threshold before final output' }, correctAnswer: 'A', explanation: 'The `detected_pattern` field creates a feedback loop: dismissed finding → look at the pattern → identify over-flagging → fix the prompt/rules.' },
  { id: 102, sectionId: 7, title: '[Real Exam] Context-Specific False Positives', text: 'After deploying automated code review, approximately 35% of flagged findings are false positives: team conventions flagged as issues, security warnings for patterns safe in your deployment context, and performance suggestions that hurt your specific use case. Which approach best enables the model to generalise to novel code patterns it has not seen before?', options: { A: 'Implement post-processing that uses keyword matching to filter out findings containing terms like "conventions" or "context-dependent"', B: 'Include few-shot examples in your prompt showing annotated code snippets that should NOT be flagged, explaining WHY they are acceptable', C: 'Create a comprehensive written specification of all patterns that should not be flagged', D: 'Add instructions to your system prompt to "be conservative" and "only flag definite issues"' }, correctAnswer: 'B', explanation: 'Few-shot examples teach the reasoning principle behind why something is acceptable. When Claude learns the principle from examples, it can apply that reasoning to new patterns it has never seen.' },
  { id: 103, sectionId: 3, title: '[Real Exam] Agentic Loop – Stop Reason', text: 'A customer contacts the agent about a warranty claim on a power drill. Resolving this requires multiple sequential tool calls: `get_customer`, `get_product`, and then either `process_refund` or `unable_to_honor`. What is the primary mechanism your application uses to determine whether to continue the loop or stop?', options: { A: 'You check the `stop_reason` field in each API response — the loop continues while it equals "tool_use" and stops when it changes to "end_turn" or another terminal value', B: 'You manually set the `tool_choice` parameter to "none" after the final expected tool call to force Claude to stop requesting tools', C: 'You track the number of tool calls made and exit the loop once a predefined maximum is reached', D: 'You check whether Claude response contains a text content block — if text is present, the agent has produced its final answer' }, correctAnswer: 'A', explanation: 'stop_reason is the official API mechanism: stop_reason = "tool_use" → execute tool and continue; stop_reason = "end_turn" → stop loop and return final response.' },
  { id: 104, sectionId: 3, title: '[Real Exam] Compliance – Hard Enforcement', text: 'Compliance requires that refunds exceeding $500 must automatically escalate to a human agent — this rule cannot be left to model discretion. However, logs show the agent occasionally processes high-value refunds directly (5% failure rate). How should you achieve guaranteed human escalation?', options: { A: 'Implement a hook to intercept tool calls: when the refund amount exceeds $500, block it and initiate human escalation programmatically', B: 'Add few-shot examples to the prompt showing correct escalation behavior at various refund amounts', C: 'Modify the refund tool to return an error with message "Amount exceeds policy limit — please transfer to human operator"', D: 'Strengthen the system prompt with emphatic language: "CRITICAL POLICY: All refunds over $500 MUST trigger human escalation"' }, correctAnswer: 'A', explanation: 'When a rule cannot be left to model discretion, enforce it in application code. A programmatic hook blocks the tool call at the infrastructure level — 100% reliable regardless of model behavior.' },
  { id: 105, sectionId: 6, title: '[Real Exam] Structured Error Metadata', text: 'Production logs reveal inconsistent error handling: when `lookup_order` fails, the agent sometimes retries (wrong for permanent errors), sometimes asks users for clarification (wrong for transient errors). Current error response: `{"isError": true, "content": [{"text": "Transaction Failed"}]}`. What change most improves error handling?', options: { A: 'Enhance error responses with structured metadata: include `errorCategory` field (transient/validation/permission) so the agent knows how to respond', B: 'Implement retry logic with exponential backoff in your MCP server for all errors, returning to the agent only after all retries are exhausted', C: 'Create an `analyze_error` MCP tool the agent calls after any failure to determine the error category and appropriate action', D: 'Add few-shot examples to the system prompt demonstrating how to interpret error message patterns and select appropriate responses' }, correctAnswer: 'A', explanation: 'The MCP server knows the error type — it should communicate that via structured metadata so the agent can retry transient errors, explain validation issues, or handle permission errors appropriately.' },
  { id: 106, sectionId: 3, title: '[Real Exam] Escalation – Explicit Customer Request', text: 'A customer sends: "This is frustrating. I have explained my issue twice and nothing is being resolved. I want to talk to a real person NOW." The agent has all customer account information and conversation history. The agent cannot resolve the specific issue anyway. What should the agent do?', options: { A: 'Acknowledge the frustration and ask one targeted question to understand the specific issue before escalating', B: 'Immediately call `escalate_to_human` with the conversation history', C: 'First call `get_customer` and `lookup_order` to gather account context, then escalate to a human agent', D: 'Briefly explain what the agent can help with and offer to resolve the issue quickly' }, correctAnswer: 'B', explanation: 'Customer explicitly demanded a human NOW, agent cannot resolve the issue, and agent already has all context. Escalate immediately with conversation history so the human agent has full context.' },
  { id: 107, sectionId: 6, title: '[Real Exam] Actionable Error Messages', text: 'Your agent uses `lookup_order` which catches all exceptions and returns a tool_result with `is_error: true` and message "That operation failed." The agent retries identically or escalates immediately. Which change gives Claude the information it needs to select the correct recovery action?', options: { A: 'Return error-type-specific messages with `is_error: true`, e.g., "Order not found (id: {id}): verify the order ID" and "Connection timeout: try lookup_order again, or use lookup_order_archive"', B: 'Implement retry logic with exponential backoff inside each tool implementation, returning normal results to the agent', C: 'Add an error classification step in the agentic loop that intercepts tool errors before Claude sees them and routes appropriately', D: 'Remove `is_error: true` and return error details as normal tool content' }, correctAnswer: 'A', explanation: 'Error messages are instructions for Claude. Specific messages enable correct decisions: "Order not found: verify order ID" → do not retry same ID; "Connection timeout: try again" → retry is valid.' },
  { id: 108, sectionId: 6, title: '[Real Exam] MCP Tool Error Handling', text: 'When implementing your `lookup_order` MCP tool, the backend sometimes returns errors (e.g., "Order not found" or temporary database failures). What is the correct way to handle these errors back to the agent?', options: { A: 'Log the error server-side and return an empty result to avoid confusing the model', B: 'Throw an exception from the tool handler so the agent framework can catch and log it', C: 'Return the error message in the tool result content with the `is_error` flag set to true', D: 'Return a success response with a "status" field indicating the error type' }, correctAnswer: 'C', explanation: 'The official Anthropic API mechanism: is_error: true + descriptive message in content. Claude knows the tool failed, knows why, and can reason about recovery.' },
  { id: 109, sectionId: 3, title: '[Real Exam] Context Management – Verbose Tool Output', text: 'Your agent has called `lookup_order` multiple times while investigating a customer return requests. Each response includes 40+ fields, making tool outputs represent the majority of the conversation context. The customer mentions two more orders they want to discuss. What is the most efficient way to avoid consuming additional context for future lookups?', options: { A: 'Move all tool responses to a vector database with semantic indexing, retrieving relevant portions as the conversation continues', B: 'Proceed with additional lookups without modifying the existing tool output content', C: 'Have the model generate a natural language summary of each order key details to replace the existing tool output context', D: 'Extract only return-relevant fields (items, purchase date, return window, return status) and replace the full tool output with just those fields' }, correctAnswer: 'D', explanation: 'For return requests, only 5-6 fields matter out of 40+. Filter tool output to return-relevant fields at extraction time — context consumption drops dramatically per lookup.' },
  { id: 110, sectionId: 3, title: '[Real Exam] Mid-Process Tool Failure', text: 'During a billing dispute resolution, your agent successfully retrieves customer info via `get_customer` and order details via `lookup_order`, but when attempting `process_refund`, it returns a timeout error. The agent has enough information to explain the charges and verify refund eligibility but cannot actually process the refund. What response best balances first-contact resolution with appropriate error handling?', options: { A: 'Explain the billing, confirm refund eligibility, acknowledge the system issue preventing immediate processing, and offer escalation or a callback', B: 'Escalate immediately to a human agent since the refund action cannot be completed', C: 'Confirm the refund will be processed and close the conversation, since the agent has all necessary information', D: 'Implement automatic retries with exponential backoff for `process_refund`, keeping the conversation open while processing' }, correctAnswer: 'A', explanation: 'Do what you can, be honest about what you cannot, provide a path forward. Customer gets billing explanation and eligibility confirmation with a clear next step.' },
  { id: 111, sectionId: 3, title: '[Real Exam] Escalation Triggers', text: 'You are implementing escalation logic for when the agent should call `escalate_to_human`. Which approach most reliably identifies cases that genuinely require human intervention?', options: { A: 'Instruct the agent to escalate when: the customer requests a human, the issue requires policy exceptions, or the agent cannot make progress toward resolution', B: 'Implement sentiment analysis that monitors for frustration indicators (negative language, exclamation marks) and triggers escalation when reaching a threshold', C: 'Build a rules engine that maps specific issue types, customer segments, and product categories to escalation decisions', D: 'Configure the agent to escalate after three consecutive tool calls that fail to resolve the customer issue' }, correctAnswer: 'A', explanation: 'Semantic escalation triggers describe actual situations where human intervention adds value: customer wants a human, policy exception needed, or no progress possible.' },
  { id: 112, sectionId: 3, title: '[Real Exam] Returning Customer – Stale Data', text: 'A customer returns 4 hours after their initial session about the same billing dispute. The previous 32-turn session contains tool results from 4 hours ago. When resuming, the agent references OLD data even after fresh tool calls return different results. What approach most reliably handles returning customers?', options: { A: 'Resume with full history and add a system prompt instruction telling the agent to always prefer the most recent tool results', B: 'Start a new session, inject a structured summary of the previous interaction (issue type, actions taken, resolution status) — forces all data lookups to be fresh', C: 'Resume with full history and configure the agent to automatically re-call all previously used tools at session start', D: 'Resume with full history but filter out previous tool result messages, keeping only the most recent tool calls' }, correctAnswer: 'B', explanation: 'New session eliminates stale tool results. Structured summary preserves customer continuity. All tool calls in the new session are 100% fresh with no anchoring to old data.' },
  { id: 113, sectionId: 3, title: '[Real Exam] Mid-Process Escalation', text: 'Your agent is handling a billing dispute. After calling `get_customer` and `lookup_order`, it identifies the dispute involves a promotional pricing error requiring manager approval — beyond the agent authorization level. How should the workflow handle this mid-process escalation?', options: { A: 'Compile a structured handoff (customer details + order info + identified issue) then call `escalate_to_human` with a reference ID', B: 'Persist the complete conversation and tool response history to a database, then call `escalate_to_human`', C: 'Attempt `process_refund` anyway, escalating only if the refund fails', D: 'Call `escalate_to_human` passing only the customer original message' }, correctAnswer: 'A', explanation: 'Preserve all gathered intelligence in a structured handoff. Human agent receives complete context: customer details, order info, root cause, and reference ID — no customer re-explanation needed.' },
  { id: 114, sectionId: 3, title: '[Real Exam] Multi-Turn Memory', text: 'The agent verifies customer identity through a multi-step process before resetting passwords. During testing, after the customer answers security questions, the agent asks them to provide their name again, as if the earlier exchange never happened. What is the most likely cause?', options: { A: 'The conversation history is not being passed in subsequent API requests', B: 'The prompt lacks instructions telling Claude to remember information across multiple exchanges', C: 'The verification tool is clearing the agent internal state after each successful validation step', D: 'Claude memory retention is limited to two conversation turns by default, requiring explicit configuration to extend' }, correctAnswer: 'A', explanation: 'Claude has zero persistent memory between API calls. If the application fails to include prior messages in the API request, Claude starts fresh every call — the most common multi-turn implementation bug.' },
  { id: 115, sectionId: 3, title: '[Real Exam] Escalation Content – What to Pass', text: 'After investigating a billing dispute over 25+ turns, you identified that duplicate charges occurred due to a payment gateway timeout. The refund exceeds your $500 authorization limit. You must call `escalate_to_human`. The human agent will not have access to your conversation history. What content should you pass?', options: { A: 'The complete conversation transcript with all tool results', B: 'Your diagnosis and the refund amount only', C: 'A structured summary: customer ID, root cause, refund amount, and recommended action', D: 'The customer original complaint verbatim plus tool result excerpts showing duplicate transactions' }, correctAnswer: 'C', explanation: 'Human agent needs exactly what they need: customer ID, root cause, refund amount, and recommended action — clean, structured, immediately actionable.' },
  { id: 116, sectionId: 3, title: '[Real Exam] Agentic Decision Making', text: 'When the agent calls `lookup_order` and receives order details showing the item was purchased 45 days ago, how does the agentic loop determine whether to call `escalate_to_human` next?', options: { A: 'The agent executes the remaining steps in a tool sequence planned at the start of the request', B: 'The order details are added to the conversation and the model reasons about which action to take next', C: 'The agent follows a pre-configured decision tree mapping order attributes to specific tool calls', D: 'The orchestration layer automatically routes to the next tool based on the order status field' }, correctAnswer: 'B', explanation: 'Core agentic loop mechanism: tool_result appended to conversation → new API call → Claude reasons about next tool or final response based on accumulated context.' },
  { id: 117, sectionId: 3, title: '[Real Exam] Guaranteeing Outcomes', text: 'Production logs show that when the agent handles complex billing disputes requiring 6+ tool calls, it sometimes exhausts its `max_turns` limit without resolving or escalating. The goal is to guarantee every interaction ends with either `process_refund` OR `escalate_to_human`. Which approach achieves this guarantee?', options: { A: 'Split the workflow into two sequential agent invocations with separate turn budgets', B: 'Implement a pre-tool-use hook that terminates the loop and escalates when approaching the maximum call count', C: 'Add system prompt instructions telling the agent to call `escalate_to_human` if the loop ends without resolution', D: 'Add orchestration layer code that checks the agent outcome after each loop terminates — if neither `process_refund` nor `escalate_to_human` was called, call `escalate_to_human` with accumulated context' }, correctAnswer: 'D', explanation: 'Post-loop safety net in application code: after loop completes for any reason, if neither target tool was called, orchestration forces escalation. Works for all termination causes including max_turns.' },
  { id: 118, sectionId: 10, title: '[Real Exam] CLAUDE.md Debugging', text: 'You documented API error handling conventions in a CLAUDE.md file at your project root. Claude Code sometimes follows these conventions and sometimes uses generic try/catch blocks. The inconsistency appears across different teams. What is the most efficient first diagnostic step?', options: { A: 'Run `/memory` to check which memory files are loaded and verify your CLAUDE.md is included', B: 'Add more detailed code examples to your CLAUDE.md with YAML frontmatter showing the exact error handling patterns', C: 'Search for conflicting instructions in `~/.claude/CLAUDE.md` that might override your project conventions', D: 'Create path-specific rules in `.claude/rules/` with YAML frontmatter specifying the error handling conventions' }, correctAnswer: 'A', explanation: '/memory shows which context files are loaded. This 5-second check answers the fundamental question: is my CLAUDE.md even in Claude context? Always diagnose before fixing.' },
  { id: 119, sectionId: 10, title: '[Real Exam] Plan Mode vs Direct Execution', text: 'A critical bug is affecting production users. Error logs show exceptions in the OrderProcessing module with a clear stack trace pointing to a specific function. No human has worked on this codebase before. What is the most effective approach?', options: { A: 'Use direct execution to examine the stack trace, read the relevant code, and implement a fix once you identify the root cause', B: 'Start with direct execution to gather initial information, then switch to plan mode to design a comprehensive solution before implementing', C: 'Use plan mode to analyze the error in context of the module architecture and dependencies before attempting any fixes', D: 'Enter plan mode to explore the module architecture and enumerate potential root causes before attempting any fixes' }, correctAnswer: 'A', explanation: 'Clear stack trace + specific function identified + production is down = direct execution. Plan mode is for ambiguous, wide-scope problems — planning overhead is waste when the stack trace hands you the answer.' },
  { id: 120, sectionId: 10, title: '[Real Exam] MCP Server Scopes', text: 'Your team is configuring MCP servers in Claude Code. You want to add a shared venue lookup server that all team members should have access to, and a personal music playlist server that only you are testing. Which configuration approach correctly applies MCP server scopes?', options: { A: 'Add both servers to your local `~/.claude.json`', B: 'Add venue server to `.mcp.json` and playlist server to `~/.claude.json`', C: 'Add both servers to the project-level `.mcp.json` file', D: 'Add venue server to `~/.claude.json` and playlist server to `.mcp.json`' }, correctAnswer: 'B', explanation: '.mcp.json (project-level) is committed to repo for all team members. ~/.claude.json (user-level) is personal machine only. Venue = shared, playlist = personal.' },
  { id: 121, sectionId: 10, title: '[Real Exam] PostToolUse Hook – Formatting', text: 'Your team CLAUDE.md includes: "Use 4-space indentation and always run Prettier formatting." Code reviews reveal roughly 15% of Claude-generated code violates this. Adding emphatic instructions reduces violations to 15% but does not eliminate them. What is the most effective way to ensure all generated code is consistently formatted?', options: { A: 'Split the formatting rules into path-scoped `.claude/rules/` files that load when Claude works on matching file types', B: 'Configure a PostToolUse hook with an Edit/Write matcher that automatically runs Prettier on each file Claude modifies', C: 'Add a Stop hook with a prompt-based check that evaluates whether generated code follows formatting standards', D: 'Extract the formatting rules into a dedicated skill with more detailed examples of correct formatting' }, correctAnswer: 'B', explanation: 'Prompt engineering ceiling has been hit at 15% violations. PostToolUse hook triggers automatically after every Edit/Write — Prettier runs regardless of what Claude generated. 100% of file writes get formatted.' },
  { id: 122, sectionId: 6, title: '[Real Exam] MCP Prompts – Slash Commands', text: 'Your team has connected a custom MCP server that provides DevOps workflow templates. The server exposes several MCP prompts along with tools. How do these MCP prompts become accessible within Claude Code?', options: { A: 'They are added to Claude Code tool registry alongside the server tools, invoked automatically by the model when relevant', B: 'They are automatically prepended to every conversation as additional system-level context', C: 'They are surfaced as @-mentionable resources alongside files, fetched and attached to your message when referenced', D: 'They appear as slash commands (e.g., `/mcp__servername__deploy_checklist`) that you can invoke with arguments' }, correctAnswer: 'D', explanation: 'MCP primitives have different access patterns: Tools → automatic calls, Resources → @-mentionable, Prompts → slash commands (/mcp__servername__promptname).' },
  { id: 123, sectionId: 10, title: '[Real Exam] Skills – Version Controlled', text: 'Your team frequently migrates React components to Vue. You want to register this as `/migrate-component`, and the workflow should stay in sync as the team iterates on it. Where should you place the skill file?', options: { A: 'In the project `.claude/settings.json` using a `skillOverrides` entry on each developer machine', B: 'In `~/.claude/skills/migrate-component/SKILL.md` at the project root, committed to version control', C: 'In `.claude/skills/migrate-component/SKILL.md` at the project root, committed to version control', D: 'As a detailed instruction block in the project root CLAUDE.md file' }, correctAnswer: 'C', explanation: '.claude/skills/ (project-level) committed to version control = shared with all team members and stays in sync. ~/.claude/skills/ is personal/local only.' },
  { id: 124, sectionId: 10, title: '[Real Exam] Bug Fixing – Test Cases', text: 'You asked Claude to write a data migration script, but the initial output does not correctly handle records with null values in required fields. What is the most efficient path to a working solution?', options: { A: 'Add "think harder about edge cases" to your prompt and request a complete rewrite of the migration logic', B: 'Manually edit the generated code to fix the null handling, then continue working with Claude on other parts', C: 'Describe the null value problem in detail and ask Claude to regenerate the entire script with improved edge case handling', D: 'Provide a test case with example input containing null values and the expected output, then ask Claude to fix it' }, correctAnswer: 'D', explanation: 'Concrete test case (input + expected output) gives Claude the most precise specification. Targeted fix for the exact failing case — no unnecessary full regeneration.' },
  { id: 125, sectionId: 10, title: '[Real Exam] Configuration Mechanism Mapping', text: 'Your team has three requirements: (1) Claude must NEVER modify files in `db/migrations/`, (2) Claude should prefer custom logging over `console.log`, (3) All TypeScript files must be auto-formatted with Prettier after every edit. All three are in CLAUDE.md. Claude sometimes violates requirement 1. How should you restructure these requirements?', options: { A: 'Add `Edit(/db/migrations/**)` to `permissions.deny` in project settings, keep logging preference in CLAUDE.md, add a PostToolUse hook for Prettier on TypeScript files', B: 'Move all three requirements into `.claude/rules/` as path-scoped rules', C: 'Rewrite all three in CLAUDE.md using stronger directive language and add a PreToolUse hook for TypeScript edits', D: 'Configure hooks for all three: PreToolUse to block db/migrations, PostToolUse to run Prettier' }, correctAnswer: 'A', explanation: 'Match requirement type to mechanism: hard prohibition → permissions.deny, behavioral preference → CLAUDE.md, automated action → PostToolUse hook.' },
  { id: 126, sectionId: 10, title: '[Real Exam] Monorepo – @imports', text: 'Your monorepo contains shared coding standards: `security-rules.md`, `api-design.md`, and a third. Your 15 packages each have different needs. Currently, package CLAUDE.md files duplicate all three standards, applying irrelevant guidance to each package. What is the most effective approach?', options: { A: 'Put all standards in the root CLAUDE.md with override instructions like "ignore security-rules.md when package does not handle user data"', B: 'Create a `shared-standards.md` that combines all three, have each package CLAUDE.md reference only relevant parts', C: 'Create `.claude/rules/` files for each standard with YAML frontmatter listing every relevant package directory', D: 'Use `@imports` in each package CLAUDE.md to reference only the specific standard files relevant to that package' }, correctAnswer: 'D', explanation: '@imports in each package CLAUDE.md: clean, DRY, each package gets exactly what it needs. Standards live in one place — updates propagate automatically.' },
  { id: 127, sectionId: 10, title: '[Real Exam] When to Use Plan Mode', text: 'You are implementing a caching layer for API responses to speed up the `/products` endpoint. You have a rough idea — Redis with a 5-minute TTL — but you are not sure what other considerations a robust implementation requires. What is the most effective way to start your iterative workflow?', options: { A: 'Start with a minimal request: "Add Redis caching to /products with 5-minute TTL." Add features and fix issues through follow-up prompts', B: 'Write a specification with your known requirements and "TBD" markers for uncertain areas', C: 'Use plan mode to analyze the current /products endpoint implementation, then provide your caching requirements before implementing', D: 'Ask Claude to interview you about the caching requirements before implementing' }, correctAnswer: 'C', explanation: 'You know what you want but not what you do not know. Plan mode on the existing endpoint surfaces cache invalidation, failure handling, and concurrency considerations before building.' },
  { id: 128, sectionId: 10, title: '[Real Exam] Plan Mode vs Direct – Simple Change', text: 'You need to add a date validation check ensuring event dates are in the future. This requires adding a conditional statement to one existing function in the reservation flow. What is the most efficient approach?', options: { A: 'Use direct execution to make the change', B: 'Start with extended thinking mode enabled to ensure thorough reasoning about the validation logic', C: 'Enter plan mode first to create a detailed implementation strategy before making the change', D: 'Enter plan mode to analyze how the validation might impact other parts of the reservation flow' }, correctAnswer: 'A', explanation: 'One conditional in one function: clear, targeted, contained change. Direct execution — just implement it. Small + clear + contained = direct execution.' },
  { id: 129, sectionId: 10, title: '[Real Exam] TDD for Iterative Refinement', text: 'You are implementing a complex graph traversal algorithm with specific performance requirements and edge cases. You want to most effectively enable progressive improvement across multiple sessions with Claude. What approach will most effectively enable this?', options: { A: 'Have Claude extensively research the algorithm and create a detailed implementation plan using extended thinking, then implement', B: 'Provide Claude with a reference implementation from documentation, then ask it to rewrite the code to match your codebase style', C: 'Provide Claude with a detailed natural language specification of the algorithm, including all requirements and edge cases', D: 'Write a test suite covering expected behavior, edge cases, and performance requirements before implementation — share test failures with each refinement request' }, correctAnswer: 'D', explanation: 'Tests are the perfect multi-session iterative refinement mechanism: same objective success criteria every session, specific failure messages enable targeted fixes, progress is measurable.' },
  { id: 130, sectionId: 10, title: '[Real Exam] Interdependent Bug Fixes', text: 'You asked Claude Code to build a PDF report generation feature. The initial output has three formatting issues: table columns too narrow, dates without proper formatting, and incorrect page break handling. These issues interact — changing column widths affects how dates display and content height affects page breaks. What is the most effective approach?', options: { A: 'Provide all three issues in a single detailed message with exact specifications for each, allowing Claude to address them together', B: 'Address the column width issue first with specific measurements, verify it works, then fix date formatting within the corrected column structure', C: 'Start fresh with a detailed prompt specifying all formatting requirements upfront, rather than fixing the specific technical issues', D: 'Show Claude an example of a correctly formatted report and ask it to match that output' }, correctAnswer: 'A', explanation: 'Interdependent bugs should be fixed simultaneously. Column widths affect date display and page breaks — sequential fixes chase a moving target. Claude accounts for all interdependencies in one coherent update.' },
  { id: 131, sectionId: 10, title: '[Real Exam] Architectural Decisions', text: 'You are tasked with adding real-time updates to the application. This could be implemented using WebSockets, Server-Sent Events, or polling, each with different infrastructure requirements. What is the most effective way to begin this task?', options: { A: 'Use direct execution to implement polling first, then evaluate whether to upgrade to WebSockets later', B: 'Start direct execution with WebSockets, then refactor if infrastructure issues arise', C: 'Enter plan mode to explore the architecture, evaluate trade-offs, and present options for team approval before implementing', D: 'Use direct execution with a prompt asking Claude to analyze all approaches and implement the one it determines is best' }, correctAnswer: 'C', explanation: 'Multiple valid architectural options with different infrastructure implications = plan mode + team approval. Humans must own architecture and infrastructure choices.' },
  { id: 132, sectionId: 10, title: '[Real Exam] Slash Commands – Team Workflow', text: 'Your team wants Claude to follow a detailed code review checklist (8 items) when reviewing pull requests — invoked when starting reviews. Claude is also used extensively for writing features, debugging, and generating documentation. Currently, developers manually paste the checklist at the start of each review session. Which approach best addresses this workflow need?', options: { A: 'Create a `/review` slash command containing the checklist, invoked when starting reviews', B: 'Create a dedicated review subagent with the checklist embedded in its configuration', C: 'Configure plan mode as the default for code review sessions', D: 'Add the checklist to the project CLAUDE.md file under a "Code Review" section' }, correctAnswer: 'A', explanation: '/review slash command = on-demand invocation. Developer types /review → checklist loaded → review begins. Does not pollute feature writing, debugging, or documentation sessions.' },
];

const questionsPath = path.join(__dirname, '..', 'ClaudeCertPractice.Api', 'Data', 'questions.json');
const bank = JSON.parse(fs.readFileSync(questionsPath, 'utf8'));

const existingIds = new Set(bank.questions.map((q) => q.id));
const duplicates = newQuestions.filter((q) => existingIds.has(q.id));
if (duplicates.length) {
  console.error('Duplicate IDs:', duplicates.map((q) => q.id));
  process.exit(1);
}

bank.questions.push(...newQuestions);
bank.totalQuestions = bank.questions.length;

fs.writeFileSync(questionsPath, JSON.stringify(bank, null, 2) + '\n');
console.log(`Added ${newQuestions.length} questions. Total: ${bank.totalQuestions}`);
